const body = $input.first().json.body || $input.first().json;
const rubro = body.rubro || 'supermercado';
const ciudad = body.ciudad || 'Argentina';
const limit = body.limit || 10;

const searchQuery = `tienda online ${rubro} ${ciudad} site:*.com.ar OR site:*.ar precios`;

return [{ json: { rubro, ciudad, limit, searchQuery } }];

const serpData = $input.first().json;
const prevData = $('Armar Query SerpAPI').first().json;
const results = serpData.organic_results || [];

const sites = results
  .filter(r => r.link && (r.link.includes('.com.ar') || r.link.includes('.ar')))
  .map(r => ({
    name: r.title?.replace(/ - .*$/, '').trim() || 'Tienda',
    url: new URL(r.link).origin,
    full_url: r.link,
    snippet: r.snippet || '',
    category: prevData.rubro,
    city: prevData.ciudad !== 'Argentina' ? prevData.ciudad : null
  }))
  .filter((v, i, a) => a.findIndex(t => t.url === v.url) === i) // dedup por dominio
  .slice(0, prevData.limit);

return [{ json: { sites, rubro: prevData.rubro, ciudad: prevData.ciudad, total: sites.length } }];

const data = $input.first().json;
const sites = data.sites || [];

if (sites.length === 0) {
  return [{ json: { skip: true } }];
}

const siteList = sites.map((s, i) => `${i+1}. Nombre: "${s.name}" | URL: ${s.url} | Descripcion: "${s.snippet}"`).join('\n');

const prompt = `Sos un experto en e-commerce argentino. Analizá estas tiendas online del rubro "${data.rubro}" y para cada una intentá adivinar los selectores CSS más probables para scrapear sus productos.

Tiendas:
${siteList}

Para cada tienda devolvé un JSON array:
[
  {
    "index": 1,
    "name": "nombre de la tienda",
    "url": "url base",
    "scraping_url": "URL más probable de su listado de productos (ej: /productos, /catalogo, /tienda)",
    "platform": "plataforma detectada (Tiendanube/WooCommerce/Shopify/Magento/custom/desconocido)",
    "product_selector": "selector CSS para el contenedor de producto",
    "name_selector": "selector CSS para nombre",
    "price_selector": "selector CSS para precio",
    "pagination_selector": "selector CSS para siguiente pagina o null",
    "confidence": "alta/media/baja"
  }
]

Para Tiendanube: product_selector suele ser .js-item-product, name suele ser .item-name, price suele ser .price__value
Para WooCommerce: product_selector suele ser .product, name .woocommerce-loop-product__title, price .price
Para Shopify: varía pero suele ser .product-card, .product-title, .price

Devolvé SOLO el JSON array.`;

return [{ json: { ...data, prompt } }];

const groqResponse = $input.first().json;
const prevData = $('Prompt Detectar Selectores').first().json;

let analyzed = [];
try {
  const content = groqResponse.choices[0].message.content;
  const jsonMatch = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) analyzed = JSON.parse(jsonMatch[0]);
} catch(e) {
  console.log('Error parseando IA:', e.message);
}

const sites = prevData.sites || [];

const storeInserts = analyzed.map(a => {
  const original = sites[a.index - 1] || {};
  return {
    name: a.name || original.name,
    url: a.scraping_url ? 
      (a.scraping_url.startsWith('http') ? a.scraping_url : original.url + a.scraping_url)
      : original.url,
    category: prevData.rubro,
    city: prevData.ciudad !== 'Argentina' ? prevData.ciudad : null,
    scraping_enabled: false, // requiere validacion manual
    scraping_config: {
      product_selector: a.product_selector || '.product',
      name_selector: a.name_selector || '.product-name',
      price_selector: a.price_selector || '.price',
      pagination: !!a.pagination_selector,
      pagination_selector: a.pagination_selector || null,
      max_pages: 3,
      platform: a.platform || 'desconocido',
      confidence: a.confidence || 'baja'
    }
  };
});

return [{ json: { store_inserts: storeInserts, total: storeInserts.length } }];

