={
  "success": true,
  "message": "{{ $('Preparar Stores para DB').first().json.total }} tiendas descubiertas y guardadas (pendientes de validacion manual)",
  "stores": {{ JSON.stringify($('Preparar Stores para DB').first().json.store_inserts) }}
}
